    public static readonly CapabilityMatrix Sns = new(
        ServiceName: "sns",
        Operations: new OperationCapability[]
        {
            new("ConfirmSubscription", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic subscriptions", "Diff: SNS confirmation tokens are not validated against an out-of-band challenge flow.", "Diff: If the token cannot be mapped back to a known subscription identifier, aws2azure returns a synthetic auto-confirmed subscription ARN for the topic." }),
            new("CreateTopic", OperationStatus.Partial, new[] { "Azure: Azure Service Bus Topics management REST API", "Diff: TopicArn is proxy-synthesised as arn:aws:sns:{sigv4-region}:000000000000:{topicName}. The account id is a stable placeholder because the proxy is not backed by an AWS account namespace.", "Diff: Only the basic topic name is honoured on create. Topic attributes supplied in the CreateTopic request are ignored for now; Azure Service Bus topic properties stay at service defaults until a later slice implements attribute mapping.", "Diff: When an SNS topic is configured with backend=EventGrid, aws2azure still creates the backing Azure Service Bus topic in this slice because subscription metadata continues to live on Service Bus. Event Grid only handles Publish / PublishBatch.", "Diff: FIFO topic semantics are deferred. This slice only accepts the non-FIFO name subset [A-Za-z0-9_-]{1,256}; .fifo names are rejected instead of creating a FIFO-equivalent Azure entity.", "Diff: Service Bus topic names are further constrained by Azure. The proxy currently validates the AWS-side subset above and does not yet surface Azure's narrower length/character restrictions separately." }),
            new("DeleteTopic", OperationStatus.Partial, new[] { "Azure: Azure Service Bus Topics management REST API", "Diff: DeleteTopic accepts only proxy-shaped ARNs of the form arn:aws:sns:{region}:{accountId}:{topicName}. The proxy currently synthesises accountId as 000000000000, but delete only uses the topic-name suffix when translating to Azure.", "Diff: The same FIFO gap as CreateTopic applies: .fifo ARNs are rejected because FIFO semantics are deferred to a later slice.", "Diff: Azure deletes are asynchronous underneath Service Bus. A successful DeleteTopic response means the topic was accepted for deletion, not necessarily that every broker-side artifact is already gone." }),
            new("GetSubscriptionAttributes", OperationStatus.Partial, new[] { "Azure: Azure Service Bus subscription description", "Diff: Protocol and Endpoint come from aws2azure's UserMetadata blob rather than native Service Bus subscription fields. Missing or invalid UserMetadata falls back to empty strings and RawMessageDelivery=false.", "Diff: ConfirmationWasAuthenticated is always true and PendingConfirmation is always false because this slice auto-confirms subscriptions.", "Diff: FilterPolicy is returned from stored UserMetadata only. FilterPolicyScope defaults to MessageAttributes when a stored filter policy has no explicit scope.", "Diff: DeliveryPolicy, EffectiveDeliveryPolicy, and RedrivePolicy are omitted because Service Bus delivery and dead-letter settings do not match the SNS attribute shapes exposed by this API." }),
            new("GetTopicAttributes", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic description", "Diff: DisplayName is always returned as an empty string because Service Bus topics do not expose an SNS-style display name.", "Diff: Policy is returned as '{}' and DeliveryPolicy / EffectiveDeliveryPolicy are omitted because this slice does not translate SNS policies onto Azure authorization or delivery settings.", "Diff: SubscriptionsConfirmed is populated from Service Bus SubscriptionCount. Pending and deleted counts are always reported as 0 because aws2azure auto-confirms subscriptions and Service Bus does not expose the SNS lifecycle split.", "Diff: KmsMasterKeyId is returned empty because Service Bus encryption is configured at the namespace level, not per topic.", "Diff: FifoTopic is inferred from a '.fifo' suffix or RequiresDuplicateDetection=true, and ContentBasedDeduplication is mapped directly from RequiresDuplicateDetection. This is only an approximation of SNS FIFO semantics.", "Diff: AWS-only attributes such as SignatureVersion and TracingConfig are omitted." }),
            new("ListSubscriptions", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic subscriptions", "Diff: NextToken is an opaque base64-encoded JSON cursor containing the current topic offset and subscription offset within that topic.", "Diff: Listing all subscriptions requires cross-topic enumeration over the Service Bus management plane and can be more expensive than native SNS ListSubscriptions." }),
            new("ListSubscriptionsByTopic", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic subscriptions", "Diff: NextToken is an opaque base64-encoded JSON cursor containing the subscription offset within the topic." }),
            new("ListTopics", OperationStatus.Partial, new[] { "Azure: Azure Service Bus Topics management REST API", "Diff: TopicArn values are proxy-synthesised as arn:aws:sns:{sigv4-region}:000000000000:{topicName}. The account id is a stable placeholder, not an AWS account namespace.", "Diff: NextToken is an opaque base64-encoded Service Bus skip counter, not an AWS-compatible cursor. Tokens only preserve the next $skip offset and do not encode any other AWS pagination semantics.", "Diff: Pagination is fixed to Azure's $top=100 management page size for this slice. When Azure returns exactly 100 topics the proxy emits NextToken=base64(skip+100); otherwise NextToken is omitted.", "Diff: FIFO topic distinction is deferred. Topics created out of band with .fifo suffixes are not specially modelled and the slice does not surface FIFO-only metadata." }),
            new("Publish", OperationStatus.Partial, new[] { "Azure: Azure Service Bus Topics / Azure Event Grid", "Diff: MessageId is a proxy-generated GUID, not an AWS-generated SNS identifier.", "Diff: SequenceNumber is returned empty because neither Azure Service Bus nor Azure Event Grid exposes an SNS-compatible sequence number on publish.", "Diff: MessageStructure=json is passed through as-is; the proxy does not filter per-protocol payloads yet.", "Diff: On the Service Bus Topics backend, MessageAttributes encode DataType in a parallel application property named '{Name}.DataType' so AWS-style attributes can be reconstructed by downstream consumers.", "Diff: On the Event Grid backend, the proxy emits the classic Event Grid schema with eventType=aws.sns.Message; CloudEvents-formatted Event Grid topics are not supported in this slice.", "Diff: On the Event Grid backend, MessageAttributes are emitted inside data.MessageAttributes as { Type, Value } objects.", "Diff: On the Event Grid backend, the Event Grid envelope subject is always the SNS TopicArn; the AWS Subject parameter is copied into data.Subject.", "Diff: On the Event Grid backend, HTTP-level publish failures are mapped to SNS per-message failure semantics by the proxy; Publish returns an SNS error while PublishBatch marks each affected entry failed.", "Diff: Subject is exposed both as the AMQP subject property and as the 'aws.sns.Subject' application property on the Service Bus Topics backend.", "Diff: MessageDeduplicationId is forwarded as the 'x-opt-deduplication-id' application property on the Service Bus Topics backend rather than a broker-native send-side field.", "Diff: MessageGroupId / MessageDeduplicationId FIFO semantics are not honoured on the Event Grid backend; the proxy drops them, logs a warning, and continues.", "Diff: Azure Service Bus and Event Grid message size limits differ from SNS; Event Grid classic schema also enforces 1 MB per event and 1 MB per HTTP batch." }),
            new("PublishBatch", OperationStatus.Partial, new[] { "Azure: Azure Service Bus Topics / Azure Event Grid", "Diff: MessageId values are proxy-generated GUIDs, not AWS-generated SNS identifiers.", "Diff: SequenceNumber is returned empty because neither Azure Service Bus nor Azure Event Grid exposes an SNS-compatible sequence number on publish.", "Diff: MessageStructure=json is passed through as-is; the proxy does not filter per-protocol payloads yet.", "Diff: On the Service Bus Topics backend, MessageAttributes encode DataType in a parallel application property named '{Name}.DataType' so AWS-style attributes can be reconstructed by downstream consumers.", "Diff: On the Event Grid backend, the proxy emits the classic Event Grid schema with eventType=aws.sns.Message; CloudEvents-formatted Event Grid topics are not supported in this slice.", "Diff: On the Event Grid backend, MessageAttributes are emitted inside data.MessageAttributes as { Type, Value } objects.", "Diff: On the Event Grid backend, returned MessageId values are the proxy-generated GUIDs used as the Event Grid envelope id fields.", "Diff: On the Event Grid backend, HTTP-level failures are mapped to per-entry Failed results for every message in the affected HTTP batch, even though Event Grid itself accepts or rejects each POST atomically.", "Diff: On the Event Grid backend, MessageGroupId / MessageDeduplicationId FIFO semantics are not honoured; the proxy drops them, logs a warning, and continues.", "Diff: PublishBatch uses best-effort per-entry outcomes over AMQP and proxied per-entry outcomes over Event Grid; partial-failure behavior can differ from AWS SNS semantics.", "Diff: Azure Service Bus and Event Grid message size limits differ from SNS; Event Grid classic schema also enforces 1 MB per event, 1 MB per HTTP batch, and 5000 events per POST." }),
            new("SetSubscriptionAttributes", OperationStatus.Partial, new[] { "Azure: Azure Service Bus subscription description", "Diff: FilterPolicy is stored only in UserMetadata in this slice. Service Bus rule-based filtering is not programmed yet, so enforcement is deferred to a later forwarding slice.", "Diff: FilterPolicyScope accepts MessageAttributes and MessageBody, but MessageBody scope is only persisted; it is not enforced yet.", "Diff: DeliveryPolicy, RedrivePolicy, and SubscriptionRoleArn are accepted as no-ops because Service Bus does not expose a matching SNS attribute contract here.", "Diff: UserMetadata updates use a simple GET → modify → PUT flow without ETag / If-Match protection, so concurrent writers can lose updates. Future work should use the Atom ETag returned by Service Bus management responses.", "Diff: Updates that would push the serialized UserMetadata payload beyond Service Bus's 1024-character limit are rejected with InvalidParameter.", "Diff: Unknown AWS attribute names return InvalidParameter." }),
            new("SetTopicAttributes", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic description", "Diff: DisplayName, Policy, DeliveryPolicy, EffectiveDeliveryPolicy, KmsMasterKeyId, SignatureVersion, and TracingConfig do not have a direct Service Bus topic equivalent in this slice and are treated as no-ops.", "Diff: ContentBasedDeduplication is backed by RequiresDuplicateDetection, but Service Bus does not allow changing that property after topic creation. aws2azure returns InvalidParameter instead of attempting an in-place update.", "Diff: Unknown AWS attribute names return InvalidParameter." }),
            new("Subscribe", OperationStatus.Partial, new[] { "Azure: Azure Service Bus topic subscriptions", "Diff: HTTPS / HTTP subscriptions are auto-confirmed immediately. SNS token-based confirmation is not implemented in this slice.", "Diff: When a deterministic subscription already exists but its stored metadata differs from the new Subscribe request, aws2azure returns the existing ARN and logs a warning instead of replacing the subscription.", "Diff: Only sqs, https, and http protocols are accepted. email, email-json, sms, lambda, application, and firehose are rejected with InvalidParameter.", "Diff: Subscriptions always live on Azure Service Bus in this slice, even for SNS topics whose Publish / PublishBatch backend is Event Grid.", "Diff: Event Grid-backed SNS topics do not fan out to those Service Bus subscriptions yet. Until a later slice adds a forwarder, subscribers created on Event Grid-backed topics will not receive published messages.", "Diff: The Microsoft Service Bus emulator does not persist or echo subscription UserMetadata, where this proxy stores Protocol/Endpoint/FilterPolicy/RawMessageDelivery. Emulator-backed integration tests therefore skip the subscription lifecycle assertions; correctness is validated against real Azure Service Bus." }),
