    public static readonly CapabilityMatrix Sqs = new(
        ServiceName: "sqs",
        Operations: new OperationCapability[]
        {
            new("AddPermission", OperationStatus.Stub, new[] { "Azure: No native Service Bus equivalent — validates queue existence and returns success.", "Diff: The Permission payload is accepted and silently dropped; there is no AWS-style cross-account access control inside the proxy. Clients relying on AddPermission to grant access should configure SB SAS rules or Azure RBAC out of band, then map them to aws2azure access keys via the config file.", "Diff: Returns 200 OK on any well-formed payload to maximise SDK compatibility — including for Actions that SQS itself rejects on standard queues. A future revision may tighten validation once the credential model exposes scoped keys." }),
            new("ChangeMessageVisibility", OperationStatus.Partial, new[] { "Azure: Azure Service Bus queue runtime REST API — POST /{queue}/messages/{messageId}/{lockToken}?api-version=2021-05 (renew-lock); AMQP — `com.microsoft:renew-lock` over the queue's `$management` request-response link; visibility=0 maps to AMQP Abandon on the receiver link.", "Diff: SB renew-lock semantics do not accept a caller-supplied duration — every renew extends by the queue's LockDuration. When the requested timeout differs from what SB grants the proxy emits the Aws2Azure-VisibilityClamped: requested=<N>;granted=<M> diagnostic header. (The header is suppressed when they agree — typical for queues whose LockDuration equals the SDK default 30 s called with VisibilityTimeout=30.)", "Diff: VisibilityTimeout=0 is supported on the AMQP transport via Abandon (immediate release, redelivery counter incremented). It is NOT supported on the REST transport — the renew still extends the lock; clients needing immediate release on REST must DeleteMessage or wait for the lock to expire.", "Diff: Verified against in-process fakes; emulator-backed end-to-end validation lands with the Service Bus emulator fixture work.", "Diff: Header format: granted-seconds is derived from `lockedUntil - DateTimeOffset.UtcNow` (rounded to whole seconds). Clock skew between the proxy host and Service Bus can shift the value by 1-2 s; consumers should treat it as a diagnostic hint, not an SLA.", "Diff: Emulator divergence: the Service Bus emulator's $management node detaches the request/response link on the first com.microsoft:renew-lock request (visible to the proxy as 'channel has been closed'). Validated against real Azure only; the integration test against the emulator is skipped with a SkipException pointing to the real-Azure smoke." }),
            new("ChangeMessageVisibilityBatch", OperationStatus.Partial, new[] { "Azure: Azure Service Bus queue runtime REST API — N parallel POST /{queue}/messages/{messageId}/{lockToken}?action=renewlock&api-version=2021-05", "Diff: SB has no per-call visibility override on REST. The proxy validates and accepts the VisibilityTimeout value but SB always extends by the queue's LockDuration. Callers needing an arbitrary new visibility must Delete+Send or rely on SetQueueAttributes to change the queue-wide LockDuration.", "Diff: VisibilityTimeout of 0 (which AWS uses to make a message immediately re-visible) is currently treated as a renewlock too — the message is not made re-visible. This divergence is tracked for Phase-2 NFR follow-up.", "Diff: Verified against in-process fakes; emulator-backed end-to-end validation lands with the SbEmulatorFixture build-out (tracked in p2-sb-emulator-fixture).", "Diff: AMQP transport (Phase 2.5): when a queue is configured with `transport: Amqp`, ChangeMessageVisibilityBatch routes to the AMQP path — each entry with VisibilityTimeout=0 abandons via the cached (session) receiver, restoring the SQS 'immediately re-visible' semantics on this path (closing the divergence above for AMQP queues). Positive VisibilityTimeout values RenewLock via the SB `$management` link (session-aware for v3 receipt handles); SB clamping is silent in the batch shape (the singular CMV emits the `Aws2Azure-VisibilityClamped` header but the batch response has no per-entry place to carry it)." }),
            new("CreateQueue", OperationStatus.Implemented, new[] { "Azure: PUT https://{namespace}.servicebus.windows.net/{queue}?api-version=2021-05 (Atom QueueDescription)", "Diff: Queue name validation enforces SQS rules (1-80 alnum/-_, '.fifo' suffix) before reaching Azure; Azure container names are stricter on some characters.", "Diff: Idempotency: an existing queue with matching attributes returns the same QueueUrl; mismatched attributes surface QueueNameExists. We compare LockDuration, TTL, MaxMessageSize, RequiresSession, RequiresDuplicateDetection — a small set vs SQS's full attribute parity.", "Diff: Slice-1 verification has only been performed against the Service Bus emulator (mcr.microsoft.com/azure-messaging/servicebus-emulator). Real-Azure validation pending before marking the op stable." }),
            new("DeleteMessage", OperationStatus.Implemented, new[] { "Azure: Azure Service Bus queue runtime REST API — DELETE /{queue}/messages/{messageId}/{lockToken}?api-version=2021-05", "Diff: If the SB lock has expired before DeleteMessage arrives, the proxy returns ReceiptHandleIsInvalid (404). AWS SQS would return success (idempotent) for already-deleted messages and an error only for genuinely invalid handles — these two cases are indistinguishable on SB REST without an extra round-trip.", "Diff: Verified against in-process fakes; emulator-backed end-to-end validation lands with Slice 4's emulator fixture build-out.", "Diff: AMQP transport (Phase 2.5 slice 8b.4c): when the queue is configured with `transport: Amqp`, DeleteMessage settles the in-flight delivery via the AMQP `accepted` outcome against the cached receiver (via the lock-token in-flight cache landed in slice 8b.4b). Cache miss — already settled, lock expired, sender-settled at receive, or delivery came from a torn-down receiver instance — surfaces as ReceiptHandleIsInvalid, identical to the REST path's 404→ReceiptHandleIsInvalid mapping. Receipt handles minted by the AMQP path (version `2`) are rejected if presented to a REST-configured queue and vice versa — a queue's transport setting is part of the handle's contract." }),
            new("DeleteMessageBatch", OperationStatus.Implemented, new[] { "Azure: Azure Service Bus queue runtime REST API — N parallel DELETE /{queue}/messages/{messageId}/{lockToken}?api-version=2021-05", "Diff: SB REST has no native batch-delete; the proxy fans out parallel DELETEs. A failing entry never aborts the batch — callers see per-entry results matching SQS semantics.", "Diff: Expired-lock vs already-deleted ambiguity from DeleteMessage applies per entry (see DeleteMessage.yaml behavior_differences).", "Diff: Verified against in-process fakes; emulator-backed end-to-end validation lands with the SbEmulatorFixture build-out (tracked in p2-sb-emulator-fixture).", "Diff: AMQP transport (Phase 2.5): when a queue is configured with `transport: Amqp`, DeleteMessageBatch routes to the AMQP path — each entry decodes the v2/v3 AMQP receipt handle minted by AMQP ReceiveMessage, looks up the cached (session) receiver via the lock-token cache, and calls `ServiceBusReceiver.CompleteAsync`. FIFO-aware: entries with different session-ids fan out to their own cached session receivers in parallel. Per-entry failures (stale handle, queue mismatch, cache miss, transport error) are surfaced as BatchResultErrorEntry items just like the REST path." }),
            new("DeleteQueue", OperationStatus.Implemented, new[] { "Azure: DELETE https://{namespace}.servicebus.windows.net/{queue}?api-version=2021-05", "Diff: Service Bus deletes the queue synchronously; AWS SQS may take up to 60 seconds of eventual consistency before the queue stops accepting messages. Callers that delete-then-recreate within seconds may need to retry on QueueDeletedRecently — not currently surfaced by the proxy.", "Diff: Unknown-queue 404 is mapped to AWS.SimpleQueueService.NonExistentQueue (HTTP 400) per SQS spec.", "Diff: Verified against Service Bus emulator only; real-Azure validation pending." }),
            new("GetQueueAttributes", OperationStatus.Partial, new[] { "Azure: GET https://{namespace}.servicebus.windows.net/{queue}?api-version=2021-05 (Atom QueueDescription)", "Diff: AttributeNames filtering happens proxy-side after the full Atom response is parsed.", "Diff: Verified against Service Bus emulator only; real-Azure validation pending." }),
            new("GetQueueUrl", OperationStatus.Implemented, new[] { "Azure: GET https://{namespace}.servicebus.windows.net/{queue}?api-version=2021-05 (existence probe)", "Diff: Returned QueueUrl is '{request-scheme}://{request-host}/000000000000/{queue}' so the AWS SDK keeps routing back to the same proxy endpoint the caller reached.", "Diff: Existence check uses Service Bus GET; an unknown queue returns AWS.SimpleQueueService.NonExistentQueue.", "Diff: Verified against Service Bus emulator only; real-Azure validation pending." }),
            new("ListDeadLetterSourceQueues", OperationStatus.Implemented, new[] { "Azure: Page through SB management GET /$Resources/queues?api-version=2021-05 and filter entries whose ForwardDeadLetteredMessagesTo equals the requested queue.", "Diff: Linear scan: the proxy issues one or more SB management GETs per ListDeadLetterSourceQueues call. On namespaces with thousands of queues this is O(N) and may be slow; the NFR phase should consider a cached reverse index.", "Diff: Verified against in-process fakes; emulator-backed validation is blocked (SB emulator does not expose management REST). Real-Azure verification pending.", "Diff: Verified against in-process fakes; emulator-backed validation is blocked (SB emulator does not expose management REST). Real-Azure verification pending." }),
            new("ListQueueTags", OperationStatus.Stub, new[] { "Azure: No native Service Bus equivalent — returns an empty Tags map after validating queue existence.", "Diff: Always returns an empty Tags map for any existing queue. Clients using tagging as a billing-allocation signal should expect zero data; an actual implementation requires a side-store (mirrors the S3 bucket-tagging trick from Phase 1 Slice 9).", "Diff: Verified against in-process fakes; emulator-backed validation is blocked (SB emulator does not expose management REST)." }),
            new("ListQueues", OperationStatus.Implemented, new[] { "Azure: GET https://{namespace}.servicebus.windows.net/$Resources/queues?api-version=2021-05&$skip=N&$top=M", "Diff: Service Bus iteration is by $skip/$top; the cursor is not stable across queue deletions. AWS SQS tokens are likewise opaque, so no public contract is broken.", "Diff: Prefix filtering happens after the page is returned, so the same NextToken may visit a partially-filtered page. This is consistent with AWS-SDK pagination but may surface fewer than MaxResults entries per call.", "Diff: Verified against Service Bus emulator only; real-Azure validation pending." }),
            new("PurgeQueue", OperationStatus.Partial, new[] { "Azure: Azure Service Bus queue runtime REST API — emulated via drain-loop of POST /{queue}/messages/head + DELETE /{queue}/messages/{id}/{lockToken}", "Diff: SB has no native purge. The proxy emulates it by draining peek-locked messages and deleting them. With a long LockDuration the drain may not be able to keep up if producers are sending faster than the proxy can delete — the 60s budget bounds wall-clock cost; the queue is therefore best-effort empty rather than guaranteed empty at the end of the call. The SQS contract guarantees a 60-second 'all messages enqueued at the time of the call will be deleted' window, which we approximate.", "Diff: The 60-second cool-down (PurgeQueueInProgress) is in-process only. Other replicas of the proxy will not observe the cool-down — a horizontally scaled deployment could allow multiple concurrent drains. Tracked for the NFR phase (shared coordination cache).", "Diff: Verified against in-process fakes; emulator-backed end-to-end validation lands with the SbEmulatorFixture build-out (tracked in p2-sb-emulator-fixture)." }),
            new("ReceiveMessage", OperationStatus.Implemented, new[] { "Azure: Azure Service Bus queue runtime REST API — POST /{queue}/messages/head?timeout={waitSeconds}&api-version=2021-05 (peek-lock semantics)", "Diff: VisibilityTimeout on ReceiveMessage cannot be set per-call — SB locks the message for the queue's configured LockDuration. The proxy validates the parameter but does not enforce it; clients needing custom per-message visibility must use ChangeMessageVisibility after receive.", "Diff: MaxNumberOfMessages > 1 is emulated by looping POST /messages/head, capped by ReceiveLoopBudget (5s) added on top of WaitTimeSeconds — the proxy may return fewer messages than requested even when the queue has more if the budget elapses.", "Diff: ApproximateFirstReceiveTimestamp and SenderId are not surfaced (SB does not provide them).", "Diff: Long polling uses SB's native server-side wait; if the first call returns empty after the wait the receive returns immediately with an empty list (no second wait). This matches SQS semantics.", "Diff: FIFO ordering gap: SQS FIFO guarantees strict per-MessageGroupId order on receive (one in-flight message per group at a time, others stay invisible until the in-flight one is deleted). SB only enforces ordering when the receiver opens a session-aware receive link (AMQP) and pins one consumer per session — semantics SB REST cannot express. As a result, ReceiveMessage on a .fifo queue surfaces MessageGroupId on each message (so application-side de-grouping still works) but does not block other messages of the same group from being delivered concurrently to different consumers. Tracked for Phase 2.5 (hand-rolled AMQP 1.0 lib).", "Diff: MessageGroupId is surfaced from BrokerProperties.SessionId; MessageDeduplicationId from BrokerProperties.MessageId. Both only appear in the response when the AttributeNames filter requests them (or 'All').", "Diff: Verified against in-process fakes; emulator-backed end-to-end validation is blocked (SB emulator does not expose runtime REST). Real-Azure validation pending — see ADR-0001.", "Diff: AMQP transport (Phase 2.5 slice 8b.4c, MessageAttributes round-trip in Phase 6 / #99): when a queue is configured with `transport: Amqp` (see ServiceBusCredentials.Queues), ReceiveMessage uses the in-process Service Bus AMQP 1.0 client via a shared connection pool. The receipt handle minted on the AMQP path is a distinct opaque format (version `2`, base64 of `{queueName, lockToken-GUID, lockedUntilUtc}`) carrying the SB lock-token directly rather than the REST messageId/lockToken pair. Long polling (WaitTimeSeconds) is honoured on the first receive; the polling-loop emulation that the REST path uses to batch up to 10 messages is replaced by a single `ReceiveBatchAsync` call against the cached AMQP link, which is more efficient. MessageAttributes (String/Number/Binary DataType round-trip) are now reconstructed from the `Aws2Azure-AttrTypes` application-property registry written by the AMQP send path; MD5OfMessageAttributes is computed via the shared `SqsMessageMd5.OfAttributes` helper so both transports produce the same hash. FIFO MessageGroupId is surfaced from `properties.group-id` (with the receiver's session-id as a fallback).", "Diff: Dead-letter attribution (AMQP path, Phase 2.5): when SB delivers a message from a `<queue>/$DeadLetterQueue` subqueue, the proxy surfaces three system attributes — `DeadLetterQueueSourceArn` (synthesised as `arn:aws:sqs:us-east-1:000000000000:<sourceQueueName>` from the SB `x-opt-deadletter-source` annotation; us-east-1 is a placeholder since the proxy doesn't model AWS regions, and the account id is `QueueUrlBuilder.PlaceholderAccountId`), `Aws2Azure-DeadLetterReason`, and `Aws2Azure-DeadLetterErrorDescription` (the latter two read from the dead-lettered message's application-properties, prefixed `Aws2Azure-` because SQS has no AWS-standard counterpart). All three respect the AttributeNames filter, are omitted entirely for non-DLQ messages, and are only emitted on the AMQP path (the REST path does not subscribe to DLQ subqueues yet).", "Diff: Emulator divergence (Phase 2.7 Slice 6): the Azure Service Bus emulator does NOT echo the broker-assigned session-id back in the receiver attach response's `com.microsoft:session-filter` when the client requests `sessionId=null` (broker-assigned). The proxy's FIFO receive path correctly fails fast in that case with `InvalidOperationException`, but it means FIFO end-to-end coverage against the emulator is impossible. Real Azure Service Bus honours the AMQP contract and echoes the id, so the production path works. FIFO IT coverage lives in the real-Azure nightly smoke instead; lifecycle ITs against the emulator skip the two FIFO scenarios.", "Diff: Emulator divergence (Phase 2.7 Slice 7): the SB emulator's TTL-expiry sweeper does not reliably dead-letter messages once their `DefaultMessageTimeToLive` elapses and/or does not honour `ForwardDeadLetteredMessagesTo` on the resulting DLQ message within an integration-test budget — observed: forwarded message never arrives on the target queue within 45s. Real Service Bus's expiry pipeline runs every ~5s and performs the forward synchronously. DLQ-forward IT coverage lives in the real-Azure nightly smoke; the slice-7 emulator-backed DLQ test is gated with `Skip.If` documenting the divergence." }),
            new("RemovePermission", OperationStatus.Stub, new[] { "Azure: No native Service Bus equivalent — validates queue existence and returns success.", "Diff: No-op: returns 200 OK regardless of the Label. See AddPermission gap doc for the underlying rationale." }),
            new("SendMessage", OperationStatus.Implemented, new[] { "Azure: Azure Service Bus queue runtime REST API — POST /{queue}/messages?api-version=2021-05", "Diff: Per-queue transport selection (Phase 2.7 Slice 2): when the credential's serviceBus.transport (or per-queue override) is set to 'amqp', SendMessage is routed natively over AMQP via ServiceBusAmqpSender. The SQS-visible behaviour is identical to the REST path — same validation, same idempotency-key contract, same MD5 algorithm — only the wire to Service Bus differs. SendMessageBatch still goes over REST (Slice 3).", "Diff: MessageId is synthesised proxy-side (SB does not echo the message id on the runtime POST). For FIFO the MessageDeduplicationId is reused as the MessageId; otherwise a fresh Guid is minted.", "Diff: FIFO required-param validation (Slice 5): on a .fifo queue, MessageGroupId is required and the proxy returns MissingParameter when it is omitted. On standard queues, MessageGroupId and MessageDeduplicationId are rejected with InvalidParameterValue — matching SQS's per-attribute domain.", "Diff: SQS attribute data types (String/Number/Binary/'String.Custom') are flattened to SB application-property strings. The proxy emits an Aws2Azure-AttrTypes side-channel header so the receive path can faithfully reconstruct the original SQS shape — without it, all attributes would surface as String on receive.", "Diff: SQS's per-message cap is 1 MiB (1,048,576 bytes) — raised from 256 KiB in August 2025 — and includes the body plus every message attribute's name + data type + value bytes. The proxy enforces the same 1 MiB cap. The *effective* cap is also bounded by the backing Service Bus tier: SB Standard rejects anything over 256 KiB regardless, SB Premium honours up to 100 MiB. Per-queue MaximumMessageSize (1024..1048576) is recorded at CreateQueue time but not re-validated per send — SB itself rejects oversized payloads.", "Diff: Payloads larger than 1 MiB must use the AWS Extended Client Library, which stores the body in S3 and embeds a JSON pointer in the SQS message. That pointer flows through this proxy unchanged: the receive side returns the same pointer, and the embedded S3 reference resolves against the proxy's S3 → Blob translation, so end-to-end large-message support works as long as the client uses the Extended Client and the same proxy fronts both S3 and SQS.", "Diff: ScheduledEnqueueTimeUtc has millisecond resolution in SB; SQS DelaySeconds is integer seconds, so no loss occurs.", "Diff: Verified against in-process fakes; end-to-end emulator validation deferred to Slice 3 where the receive path co-validates send. Real-Azure verification pending." }),
            new("SendMessageBatch", OperationStatus.Implemented, new[] { "Azure: Azure Service Bus queue runtime REST API — POST /{queue}/messages with Content-Type: application/vnd.microsoft.servicebus.json", "Diff: Per-queue transport selection (Phase 2.7 Slice 3): when the credential's serviceBus.transport (or per-queue override) is set to 'amqp', SendMessageBatch dispatches each entry over a single AMQP sender link and aggregates the per-transfer dispositions. Unlike the REST path, this gives real per-entry partial-failure granularity — one rejected entry surfaces in Failed[] while the others remain Successful. Validation, FIFO interlock, idempotency-key minting, MD5 and response shape are otherwise identical to REST.", "Diff: SB's runtime batch send is atomic: the whole batch either succeeds or fails together (no AMQP-style per-message ack). The proxy preserves SQS's BatchResultErrorEntry shape: on a batch-level SB error every entry surfaces in Failed[] with the mapped SQS error code (SenderFault=true for client-side rejections, false for server-side). Genuine per-entry partial success (one bad entry mixed with good ones) is not available over SB REST.", "Diff: FIFO required-param validation (Slice 5): on a .fifo queue, every entry must carry a MessageGroupId; the proxy rejects the whole batch with MissingParameter on the first violating entry (validation runs before the SB call). On standard queues, MessageGroupId / MessageDeduplicationId on any entry yields InvalidParameterValue.", "Diff: Same attribute-flattening + Aws2Azure-AttrTypes side-channel as SendMessage. The 1 MiB aggregate cap is computed over body + attribute name/type/value bytes per the SQS quota docs (raised from 256 KiB in August 2025).", "Diff: Payloads larger than 1 MiB require the AWS Extended Client Library (S3-backed pointer); the same caveat as SendMessage applies — the pointer flows through unchanged and resolves against the proxy's S3 → Blob translation.", "Diff: Entry MessageId returned to the caller is proxy-synthesised (Guid, or MessageDeduplicationId for FIFO).", "Diff: Verified against in-process fakes; end-to-end emulator validation deferred to Slice 3." }),
            new("SetQueueAttributes", OperationStatus.Partial, new[] { "Azure: Azure Service Bus management REST API — PUT /{queue}?api-version=2021-05 with If-Match: * (whole-entity replace)", "Diff: Updates are not atomic across multiple concurrent SetQueueAttributes calls on the same queue: last write wins. If-Match: * is used (not the ETag we read) because SB does not surface the ETag in management responses on every emulator/version we tested. NFR phase may tighten this with an If-Match: <etag>.", "Diff: Several SQS-only attributes have no SB equivalent (Policy, KmsMasterKeyId, KmsDataKeyReusePeriodSeconds, SqsManagedSseEnabled, RedriveAllowPolicy). The proxy rejects them with InvalidAttributeName until Slice 5 (RedrivePolicy) and the security-encryption pass land.", "Diff: FIFO-only attributes (FifoQueue, FifoThroughputLimit, DeduplicationScope) cannot be flipped on an existing queue (SB rejects the change); the proxy returns InvalidAttributeName.", "Diff: Verified against in-process fakes; emulator-backed end-to-end validation is blocked because the Service Bus emulator does not expose the management REST API. Real-Azure validation pending." }),
